// Canadian Federal Tax Calculator 2024
// Inputs come from the AI agent as JSON arguments
const args = JSON.parse($input.first().json.query || '{}');

const income = parseFloat(args.income) || 0;
const rrsp = parseFloat(args.rrspContribution) || 0;
const province = args.province || 'Not specified';
const taxableIncome = Math.max(0, income - rrsp);

// 2024 Federal tax brackets
const federalBrackets = [
  { limit: 55867,   rate: 0.15  },
  { limit: 111733,  rate: 0.205 },
  { limit: 154906,  rate: 0.26  },
  { limit: 220000,  rate: 0.29  },
  { limit: Infinity, rate: 0.33 },
];

// 2024 Provincial top marginal rates (approximate — for reference)
const provincialTopRates = {
  'AB': 0.15, 'BC': 0.205, 'MB': 0.174, 'NB': 0.198,
  'NL': 0.218, 'NS': 0.21, 'NT': 0.1405, 'NU': 0.1195,
  'ON': 0.1316, 'PE': 0.165, 'QC': 0.2575, 'SK': 0.145, 'YT': 0.15
};

function calcTax(income, brackets) {
  let tax = 0, prev = 0;
  for (const b of brackets) {
    if (income <= 0) break;
    const chunk = Math.min(income, b.limit - prev);
    tax += chunk * b.rate;
    income -= chunk;
    prev = b.limit;
  }
  return tax;
}

// 2024 Basic Personal Amount
const BPA = 15705;
const federalTax = calcTax(Math.max(0, taxableIncome - BPA), federalBrackets);
const bpaTaxCredit = BPA * 0.15; // 15% credit on BPA
const netFederalTax = Math.max(0, federalTax - bpaTaxCredit);

// Find marginal bracket
const marginalBracket = federalBrackets.find(b => taxableIncome <= b.limit);
const marginalRate = marginalBracket ? marginalBracket.rate : 0.33;
const rrspTaxSaving = rrsp * marginalRate;

// Capital gains note (2024 budget change)
let capitalGainsNote = '';
if (income > 250000) {
  capitalGainsNote = 'Note: Capital gains above $250,000 are now included at 2/3 (66.67%) per 2024 federal budget.';
}

return [{
  json: {
    inputs: { grossIncome: income, rrspContribution: rrsp, province },
    results: {
      taxableIncome: Math.round(taxableIncome),
      estimatedFederalTax: Math.round(netFederalTax),
      marginalFederalRate: `${(marginalRate * 100).toFixed(1)}%`,
      effectiveFederalRate: income > 0 ? `${((netFederalTax / income) * 100).toFixed(2)}%` : '0%',
      rrspTaxSaving: Math.round(rrspTaxSaving),
      basicPersonalAmount: BPA,
    },
    provincialNote: province !== 'Not specified'
      ? `Provincial tax for ${province} not included in calculation. Approximate top provincial rate: ${provincialTopRates[province.toUpperCase()] ? (provincialTopRates[province.toUpperCase()] * 100).toFixed(2) + '%' : 'look up current rate on CRA website'}.`
      : 'Please provide province for a more complete estimate.',
    capitalGainsNote,
    disclaimer: 'This is a simplified federal estimate only. Consult a tax professional for complete advice. Source: CRA T1 General 2024.'
  }
}];

// CRA Contribution Limits & Key Thresholds
// Data accurate as of 2024/2025 tax years

const limits = {
