      note: 'Government matches 20% on first $2,500/year per child (max $500 CESG/year). Lifetime CESG max $7,200.'
    },
    CPP: {
      maximumPensionableEarnings: 68500,
      basicExemption: 3500,
      employeeRate: 0.0595,
      maximumContribution: 3867,
      CPP2threshold: 73200,
      CPP2rate: 0.04,
      note: 'CPP2 applies on earnings between $68,500 and $73,200 at 4%.'
    },
    EI: {
      maximumInsurableEarnings: 63200,
      employeeRate: 0.0166,
      maximumPremium: 1049,
      note: 'EI premiums capped at maximum insurable earnings.'
    },
    capitalGains: {
      inclusionRateBelow250k: 0.50,
      inclusionRateAbove250k: 0.6667,
      lifetimeCapitalGainsExemption: 1250000,
      note: '2024 budget increased inclusion rate to 2/3 on capital gains exceeding $250,000/year for individuals.'
    },
    smallBusiness: {
      SBDRate: 0.09,
      generalCorporateRate: 0.15,
